Algorithme TourCirculaire;
Var
    N, i : Entier;
    P[100000], D[100000] : Entier;
    total, tank, start : Entier;
Debut
    Lire(N);
    Pour i := 0 a N - 1 Faire
        Lire(P[i], D[i]);
    FinPour

    total := 0;
    tank := 0;
    start := 0;

    Pour i := 0 a N - 1 Faire
        total := total + (P[i] - D[i]);
        tank := tank + (P[i] - D[i]);

        Si tank < 0 Alors
            start := i + 1;
            tank := 0;
        FinSi
    FinPour

    Si total >= 0 Alors Ecrire(start); Sinon Ecrire(-1); FinSi
Fin.
